/*  void    vd_g_Fpcall_vd_Fvd(const FP_VD_FVD * fp_ap_VD_FVD, const U2 u2_a_NC)                                                     */
/* --------------------------------------------------------------------------------------------------------------------------------- */
/*  Arguments:      -                                                                                                                */
/*  Return:         -                                                                                                                */
/*===================================================================================================================================*/
void    vd_g_Fpcall_vd_Fvd(const FP_VD_FVD * fp_ap_VD_FVD, const U2 u2_a_NC)
{
    U4     u4_t_lpcnt;

    for(u4_t_lpcnt = (U4)0U; u4_t_lpcnt < (U4)u2_a_NC; u4_t_lpcnt++){
        (*fp_ap_VD_FVD[u4_t_lpcnt])();
    }
}
